CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;
CREATE TABLE tenants (
    "Id" uuid NOT NULL,
    "Name" character varying(150) NOT NULL,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_tenants" PRIMARY KEY ("Id")
);

CREATE TABLE audit_logs (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "TenantId" uuid,
    "TableName" character varying(100) NOT NULL,
    "RecordId" integer NOT NULL,
    "DeletedData" jsonb NOT NULL,
    "DeletedAt" timestamp without time zone,
    CONSTRAINT "PK_audit_logs" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_audit_logs_tenants_TenantId" FOREIGN KEY ("TenantId") REFERENCES tenants ("Id") ON DELETE CASCADE
);

CREATE TABLE users (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "TenantId" uuid,
    "Email" character varying(100) NOT NULL,
    "PasswordHash" text NOT NULL,
    "PasswordSalt" text NOT NULL,
    "Role" character varying(50) NOT NULL,
    "CreatedAt" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_users" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_users_role" CHECK ("Role" IN ('Owner','Manager','User','SuperAdmin','Admin')),
    CONSTRAINT "FK_users_tenants_TenantId" FOREIGN KEY ("TenantId") REFERENCES tenants ("Id") ON DELETE SET NULL
);

CREATE TABLE notifications (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer NOT NULL,
    "Message" text NOT NULL,
    "IsRead" boolean NOT NULL DEFAULT FALSE,
    "CreatedAt" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_notifications" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_notifications_users_UserId" FOREIGN KEY ("UserId") REFERENCES users ("Id") ON DELETE CASCADE
);

CREATE TABLE restaurants (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "TenantId" uuid NOT NULL,
    "Name" character varying(100) NOT NULL,
    "Location" character varying(255) NOT NULL,
    "OwnerId" integer,
    "ManagerId" integer,
    CONSTRAINT "PK_restaurants" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_restaurants_tenants_TenantId" FOREIGN KEY ("TenantId") REFERENCES tenants ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_restaurants_users_ManagerId" FOREIGN KEY ("ManagerId") REFERENCES users ("Id") ON DELETE SET NULL,
    CONSTRAINT "FK_restaurants_users_OwnerId" FOREIGN KEY ("OwnerId") REFERENCES users ("Id") ON DELETE SET NULL
);

CREATE TABLE inventory (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "RestaurantId" integer NOT NULL,
    "CreatedAt" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_inventory" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_inventory_restaurants_RestaurantId" FOREIGN KEY ("RestaurantId") REFERENCES restaurants ("Id") ON DELETE CASCADE
);

CREATE TABLE menu_of_restaurant (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "RestaurantId" integer NOT NULL,
    "Name" character varying(100) NOT NULL,
    CONSTRAINT "PK_menu_of_restaurant" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_menu_of_restaurant_restaurants_RestaurantId" FOREIGN KEY ("RestaurantId") REFERENCES restaurants ("Id") ON DELETE CASCADE
);

CREATE TABLE reports (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "Type" character varying(50) NOT NULL,
    "RestaurantId" integer NOT NULL,
    "Message" character varying(1000) NOT NULL,
    "CreatedAt" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_reports" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_reports_restaurants_RestaurantId" FOREIGN KEY ("RestaurantId") REFERENCES restaurants ("Id") ON DELETE CASCADE
);

CREATE TABLE reviews (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer,
    "RestaurantId" integer NOT NULL,
    "Rating" integer NOT NULL,
    "Comment" character varying(1000),
    "CreatedAt" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_reviews" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_reviews_rating" CHECK ("Rating" >= 1 AND "Rating" <= 5),
    CONSTRAINT "FK_reviews_restaurants_RestaurantId" FOREIGN KEY ("RestaurantId") REFERENCES restaurants ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_reviews_users_UserId" FOREIGN KEY ("UserId") REFERENCES users ("Id") ON DELETE SET NULL
);

CREATE TABLE staff (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" integer NOT NULL,
    "RestaurantId" integer NOT NULL,
    "Position" character varying(50) NOT NULL,
    CONSTRAINT "PK_staff" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_staff_restaurants_RestaurantId" FOREIGN KEY ("RestaurantId") REFERENCES restaurants ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_staff_users_UserId" FOREIGN KEY ("UserId") REFERENCES users ("Id") ON DELETE CASCADE
);

CREATE TABLE suppliers (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "RestaurantId" integer NOT NULL,
    "Name" character varying(100) NOT NULL,
    "Contact" character varying(100),
    CONSTRAINT "PK_suppliers" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_suppliers_restaurants_RestaurantId" FOREIGN KEY ("RestaurantId") REFERENCES restaurants ("Id") ON DELETE CASCADE
);

CREATE TABLE menu_items (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "MenuId" integer NOT NULL,
    "Name" character varying(100) NOT NULL,
    "Price" numeric(10,2) NOT NULL,
    "Description" text,
    "CookingTime" integer NOT NULL,
    CONSTRAINT "PK_menu_items" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_menu_items_cooking_time" CHECK ("CookingTime" >= 0),
    CONSTRAINT "CK_menu_items_price" CHECK ("Price" >= 0),
    CONSTRAINT "FK_menu_items_menu_of_restaurant_MenuId" FOREIGN KEY ("MenuId") REFERENCES menu_of_restaurant ("Id") ON DELETE CASCADE
);

CREATE TABLE shifts (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "StaffId" integer NOT NULL,
    "StartTime" timestamp without time zone NOT NULL,
    "EndTime" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_shifts" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_shifts_time" CHECK ("EndTime" > "StartTime"),
    CONSTRAINT "FK_shifts_staff_StaffId" FOREIGN KEY ("StaffId") REFERENCES staff ("Id") ON DELETE CASCADE
);

CREATE TABLE tables (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "RestaurantId" integer NOT NULL,
    "Number" integer NOT NULL,
    "Capacity" integer NOT NULL,
    "Status" character varying(50) NOT NULL,
    "AssignedStaffId" integer,
    CONSTRAINT "PK_tables" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_tables_capacity" CHECK ("Capacity" > 0),
    CONSTRAINT "FK_tables_restaurants_RestaurantId" FOREIGN KEY ("RestaurantId") REFERENCES restaurants ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_tables_staff_AssignedStaffId" FOREIGN KEY ("AssignedStaffId") REFERENCES staff ("Id") ON DELETE SET NULL
);

CREATE TABLE inventory_items (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "InventoryId" integer NOT NULL,
    "ItemName" character varying(100) NOT NULL,
    "Quantity" numeric(10,2) NOT NULL,
    "SupplierId" integer,
    "UnitPrice" numeric(10,2) NOT NULL,
    "CreatedAt" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_inventory_items" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_inventory_items_quantity" CHECK ("Quantity" >= 0),
    CONSTRAINT "CK_inventory_items_unit_price" CHECK ("UnitPrice" >= 0),
    CONSTRAINT "FK_inventory_items_inventory_InventoryId" FOREIGN KEY ("InventoryId") REFERENCES inventory ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_inventory_items_suppliers_SupplierId" FOREIGN KEY ("SupplierId") REFERENCES suppliers ("Id") ON DELETE SET NULL
);

CREATE TABLE purchase_orders (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "RestaurantId" integer NOT NULL,
    "SupplierId" integer NOT NULL,
    "Total" numeric(10,2) NOT NULL,
    "CreatedAt" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_purchase_orders" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_purchase_orders_total" CHECK ("Total" >= 0),
    CONSTRAINT "FK_purchase_orders_restaurants_RestaurantId" FOREIGN KEY ("RestaurantId") REFERENCES restaurants ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_purchase_orders_suppliers_SupplierId" FOREIGN KEY ("SupplierId") REFERENCES suppliers ("Id") ON DELETE RESTRICT
);

CREATE TABLE orders (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "TableId" integer NOT NULL,
    "Status" character varying(50) NOT NULL,
    "Total" numeric(10,2) NOT NULL,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
    CONSTRAINT "PK_orders" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_orders_total" CHECK ("Total" >= 0),
    CONSTRAINT "FK_orders_tables_TableId" FOREIGN KEY ("TableId") REFERENCES tables ("Id") ON DELETE CASCADE
);

CREATE TABLE reservations (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "TableId" integer NOT NULL,
    "ReservationDate" date NOT NULL,
    "ReservationTime" time without time zone NOT NULL,
    "Name" character varying(100) NOT NULL,
    "Phone" text,
    "Status" character varying(50) NOT NULL,
    CONSTRAINT "PK_reservations" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_reservations_tables_TableId" FOREIGN KEY ("TableId") REFERENCES tables ("Id") ON DELETE CASCADE
);

CREATE TABLE kitchen_queue (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "OrderId" integer NOT NULL,
    "UpdatedAt" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_kitchen_queue" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_kitchen_queue_orders_OrderId" FOREIGN KEY ("OrderId") REFERENCES orders ("Id") ON DELETE CASCADE
);

CREATE TABLE order_items (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "OrderId" integer NOT NULL,
    "MenuItemId" integer NOT NULL,
    "Quantity" integer NOT NULL,
    "Price" numeric(10,2) NOT NULL,
    CONSTRAINT "PK_order_items" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_order_items_price" CHECK ("Price" >= 0),
    CONSTRAINT "CK_order_items_quantity" CHECK ("Quantity" > 0),
    CONSTRAINT "FK_order_items_menu_items_MenuItemId" FOREIGN KEY ("MenuItemId") REFERENCES menu_items ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_order_items_orders_OrderId" FOREIGN KEY ("OrderId") REFERENCES orders ("Id") ON DELETE CASCADE
);

CREATE TABLE payments (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "OrderId" integer NOT NULL,
    "Amount" numeric(10,2) NOT NULL,
    "Method" character varying(50) NOT NULL,
    "Status" character varying(50) NOT NULL,
    "CreatedAt" timestamp without time zone NOT NULL,
    CONSTRAINT "PK_payments" PRIMARY KEY ("Id"),
    CONSTRAINT "CK_payments_amount" CHECK ("Amount" >= 0),
    CONSTRAINT "FK_payments_orders_OrderId" FOREIGN KEY ("OrderId") REFERENCES orders ("Id") ON DELETE CASCADE
);

