for all
to app_authenticated
using (
    current_setting('app.current_user_role', true) = 'SuperAdmin'
    or "TenantId" = nullif(current_setting('app.current_tenant_id', true), '')::uuid
)
with check (
    current_setting('app.current_user_role', true) = 'SuperAdmin'
    or "TenantId" = nullif(current_setting('app.current_tenant_id', true), '')::uuid
);

